gsap.registerPlugin(ScrollTrigger);

const lenis = new Lenis();
lenis.on("scroll", ScrollTrigger.update);
gsap.ticker.add((time) => {
  lenis.raf(time * 1000);
});

gsap.ticker.lagSmoothing(0);

const pinnedSection = document.querySelector(".pinned");
const stickyHeader = document.querySelector(".sticky-header");
const cards = document.querySelectorAll(".card");
const progressBarContainer = document.querySelector(".progress-bar");
const progressBar = document.querySelector(".progress");
const indicesContainer = document.querySelector(".indices");
const indices = document.querySelectorAll(".index");
const cardCount = cards.length;
const pinnedHeight = window.innerHeight * (cardCount + 1);
const startRotations = [0, 5, 0, -5];
const endRotations = [-10, -5, 10, 5];
const progressColors = ["#ecb74c", "#7dd8cd", "#e0ff57", "#7dd8cd"];

cards.forEach((card, index) => {
  gsap.set(card, { rotation: startRotations[index] });
});

let isProgressBarVisible = false;
let currentActiveIndex = -1;

function animateIndexOpacity(newIndex) {
  if (newIndex !== currentActiveIndex) {
    indices.forEach((index, i) => {
      gsap.to(index, {
        opacity: i === newIndex ? 1 : 0.25,
        duration: 0.5,
        ease: "power2.out",
      });
    });
    currentActiveIndex = newIndex;
  }
}

function showProgressAndIndices() {
  gsap.to([progressBarContainer, indicesContainer], {
    opacity: 1,
    duration: 0.5,
    ease: "power2.out",
  });
  isProgressBarVisible = true;
}

function hideProgressAndIndices() {
  gsap.to([progressBarContainer, indicesContainer], {
    opacity: 0,
    duration: 0.5,
    ease: "power2.out",
  });
  isProgressBarVisible = false;
  animateIndexOpacity(-1);
}

ScrollTrigger.create({
  trigger: pinnedSection,
  start: "top top",
  end: `+=${pinnedHeight}`,
  pin: true,
  pinSpacing: true,
  onLeave: () => {
    hideProgressAndIndices();
  },
  onEnterBack: () => {
    showProgressAndIndices();
  },
  onUpdate: (self) => {
    const progress = self.progress * (cardCount + 1);
    const currentCard = Math.floor(progress);

    if (progress <= 1) {
      gsap.to(stickyHeader, {
        opacity: 1 - progress,
        duration: 0.1,
        ease: "none",
      });
    } else {
      gsap.set(stickyHeader, { opacity: 0 });
    }

    if (progress > 1 && !isProgressBarVisible) {
      showProgressAndIndices();
    } else if (progress <= 1 && isProgressBarVisible) {
      hideProgressAndIndices();
    }

    let progressHeight = 0;
    let colorIndex = -1;
    if (progress > 1) {
      progressHeight = ((progress - 1) / cardCount) * 100;
      colorIndex = Math.min(Math.floor(progress - 1), cardCount - 1);
    }

    gsap.to(progressBar, {
      height: `${progressHeight}%`,
      backgroundColor: progressColors[colorIndex],
      duration: 0.3,
      ease: "power1.out",
    });

    if (isProgressBarVisible) {
      animateIndexOpacity(colorIndex);
    }

    cards.forEach((card, index) => {
      if (index < currentCard) {
        gsap.set(card, {
          top: "50%",
          rotation: endRotations[index],
        });
      } else if (index === currentCard) {
        const cardProgress = progress - currentCard;
        const newTop = gsap.utils.interpolate(150, 50, cardProgress);
        const newRotation = gsap.utils.interpolate(
          startRotations[index],
          endRotations[index],
          cardProgress
        );
        gsap.set(card, {
          top: `${newTop}%`,
          rotation: newRotation,
        });
      } else {
        gsap.set(card, {
          top: "150%",
          rotation: startRotations[index],
        });
      }
    });
  },
});

code.styles.css:
::-webkit-scrollbar {
  display: none;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  width: 100%;
  height: 600vh;
  font-family: "Absolut Headline Web 2021";
  color: #fff;
}

img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

section {
  width: 100vw;
  height: 100vh;
  overflow: hidden;
  background-color: #000;
}

.hero {
  background: url(./assets/hero.jpg) no-repeat 50% 50%;
  background-size: cover;
}

.footer {
  display: flex;
  justify-content: center;
  align-items: center;
}

.footer h1 {
  font-size: 4vw;
  font-weight: lighter;
  color: #fff;
  text-align: center;
}

.sticky-header {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  opacity: 1;
}

.sticky-header h1 {
  font-size: 20vw;
  font-weight: lighter;
  color: transparent;
  -webkit-text-stroke: 2px #fff;
  text-align: center;
}

.card {
  position: absolute;
  top: 150%;
  left: 50%;
  transform: translate(-50%, -50%) rotate(0deg);
  width: 40%;
  height: 50%;
  display: flex;
  justify-content: center;
  align-items: center;
  background-color: #000;
  border-radius: 1em;
  will-change: transform;
  overflow: hidden;
}

#card-1 {
  background: url(./assets/card-1.png) no-repeat 50% 50%;
  background-size: cover;
  border: 2px solid rgba(236, 183, 76, 0.35);
}

#card-2 {
  background: url(./assets/card-2.png) no-repeat 50% 50%;
  background-size: cover;
  border: 2px solid rgba(125, 216, 205, 0.35);
}

#card-3 {
  background: url(./assets/card-3.png) no-repeat 50% 50%;
  background-size: cover;
  border: 2px solid rgba(224, 255, 87, 0.35);
}

#card-4 {
  background: url(./assets/card-4.png) no-repeat 50% 50%;
  background-size: cover;
  border: 2px solid rgba(125, 216, 205, 0.35);
}

.card-phase {
  position: absolute;
  top: 1em;
  left: 50%;
  transform: translateX(-50%);
  padding: 0.125em 0.25em;
  border-radius: 0.25em;
  color: #000;
}

.card-phase p {
  font-size: 24px;
}

#card-1 .card-phase {
  background-color: #ecb74c;
}
#card-2 .card-phase {
  background-color: #7dd8cd;
}
#card-3 .card-phase {
  background-color: #e0ff57;
}
#card-4 .card-phase {
  background-color: #7dd8cd;
}

.card-title {
  text-align: center;
}

.card-title p {
  font-size: 36px;
}

.card-title h1 {
  font-size: 80px;
  font-weight: lighter;
  line-height: 90%;
}

#card-1 .card-title {
  color: #ecb74c;
}
#card-2 .card-title {
  color: #7dd8cd;
}
#card-3 .card-title {
  color: #e0ff57;
}
#card-4 .card-title {
  color: #7dd8cd;
}

.card-title h1 span {
  color: transparent;
  -webkit-text-stroke: 1.25px #fff;
}

.progress-bar {
  position: absolute;
  top: 0;
  right: 0;
  width: 8px;
  height: 100%;
  background-color: #fff;
  opacity: 0;
}

.progress-bar::after {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgb(0, 0, 0);
  background: linear-gradient(
    180deg,
    rgba(0, 0, 0, 1) 0%,
    rgba(0, 0, 0, 0) 20%,
    rgba(0, 0, 0, 0) 50%,
    rgba(0, 0, 0, 0) 80%,
    rgba(0, 0, 0, 1) 100%
  );
}

.progress {
  width: 100%;
  height: 0%;
  background-color: #353531;
}

.indices {
  position: absolute;
  top: 0;
  right: 24px;
  height: 100%;
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: 4em;
  opacity: 0;
}

.index {
  text-align: right;
  opacity: 0.25;
}

.index p {
  text-decoration: line-through;
  text-transform: uppercase;
  font-size: 0.95rem;
}

.index p:nth-child(2) {
  font-family: "Absolut Sans 2021";
  font-size: 0.95rem;
}

.index p:nth-child(3) {
  font-family: "Absolut Headline Web 2021";
  font-size: 1.125rem;
}

#index-1 p {
  color: #ecb74c;
}
#index-2 p {
  color: #7dd8cd;
}
#index-3 p {
  color: #e0ff57;
}
#index-4 p {
  color: #7dd8cd;
}

.lenis.lenis-smooth {
  scroll-behavior: auto !important;
}

.lenis.lenis-smooth [data-lenis-prevent] {
  overscroll-behavior: contain;
}

.lenis.lenis-stopped {
  overflow: hidden;
}

.lenis.lenis-smooth iframe {
  pointer-events: none;
}

@media (max-width: 900px) {
  .card {
    width: 75%;
    height: 40%;
  }

  .card-phase p {
    font-size: 18px;
  }

  .card-title p {
    font-size: 24px;
  }

  .card-title h1 {
    font-size: 40px;
  }

  .card-title h1 span {
    -webkit-text-stroke: 0.75px #fff;
  }

  .indices {
    right: 15px;
  }

  .index p:nth-child(2),
  .index p:nth-child(3) {
    display: none;
  }

  .footer h1 {
    font-size: 8vw;
  }
}
